# DONUT CHART  (reusable — takes any list of (label, value, colour) slices)
# ==============================================================================
class _DonutChart(QtWidgets.QWidget):
    def __init__(self, slices: list, centre_label: str = "Total", parent=None):
        super().__init__(parent)
        self.setMinimumSize(150, 150)
        self._slices = slices
        self._total = sum(s[1] for s in slices) or 1
        self._centre_label = centre_label

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)
        w, h = self.width(), self.height()
        size = min(w, h) - 14
        x = (w - size) // 2
        y = (h - size) // 2
        rect = QtCore.QRectF(x, y, size, size)
        start = 90 * 16
        for _, val, col in self._slices:
            span = int(round(val / self._total * 360 * 16))
            p.setBrush(QtGui.QColor(col))
            p.setPen(Qt.PenStyle.NoPen)
            p.drawPie(rect, start, -span)
            start -= span
        hole = size * 0.56
        hx = (w - hole) / 2
        hy = (h - hole) / 2
        p.setBrush(QtGui.QColor(_WHITE))
        p.drawEllipse(QtCore.QRectF(hx, hy, hole, hole))
        p.setPen(QtGui.QColor(_TEXT_DARK))
        p.setFont(QtGui.QFont("Segoe UI", 16, QtGui.QFont.Weight.Bold))
        p.drawText(QtCore.QRectF(hx, hy - 6, hole, hole / 2 + 6),
                   Qt.AlignmentFlag.AlignCenter, str(self._total))
        p.setFont(QtGui.QFont("Segoe UI", 8))
        p.setPen(QtGui.QColor(_TEXT_GREY))
        p.drawText(QtCore.QRectF(hx, hy + hole / 2 - 10, hole, 16),
                   Qt.AlignmentFlag.AlignCenter, self._centre_label)
        p.end()


