# GAUGE PERCENT  (Clearance Completion Rate — progress-ring style donut)
# ==============================================================================
class _GaugePercent(QtWidgets.QWidget):
    def __init__(self, percent: float, colour: str, label: str = "Completed",
                 track_colour: str = "#e5e7eb", parent=None):
        super().__init__(parent)
        self.setMinimumSize(140, 140)
        self._pct = max(0.0, min(100.0, percent))
        self._colour = colour
        self._track = track_colour
        self._label = label

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)
        w, h = self.width(), self.height()
        size = min(w, h) - 14
        x = (w - size) // 2
        y = (h - size) // 2
        rect = QtCore.QRectF(x, y, size, size)

        p.setPen(Qt.PenStyle.NoPen)
        p.setBrush(QtGui.QColor(self._track))
        p.drawPie(rect, 0, 360 * 16)

        span = int(round(self._pct / 100 * 360 * 16))
        p.setBrush(QtGui.QColor(self._colour))
        p.drawPie(rect, 90 * 16, -span)

        hole = size * 0.62
        hx = (w - hole) / 2
        hy = (h - hole) / 2
        p.setBrush(QtGui.QColor(_WHITE))
        p.drawEllipse(QtCore.QRectF(hx, hy, hole, hole))

        p.setPen(QtGui.QColor(_TEXT_DARK))
        p.setFont(QtGui.QFont("Segoe UI", 17, QtGui.QFont.Weight.Bold))
        p.drawText(QtCore.QRectF(hx, hy - 6, hole, hole / 2 + 6),
                   Qt.AlignmentFlag.AlignCenter, f"{self._pct:.2f}%")
        p.setFont(QtGui.QFont("Segoe UI", 8))
        p.setPen(QtGui.QColor(_TEXT_GREY))
        p.drawText(QtCore.QRectF(hx, hy + hole / 2 - 10, hole, 16),
                   Qt.AlignmentFlag.AlignCenter, self._label)
        p.end()


# ==============================================================================
# MULTI-LINE CHART  (Clearance Status Trend)
# ==============================================================================
class _MultiLineChart(QtWidgets.QWidget):
    def __init__(self, x_labels: list, series: list, y_max: int = 25,
                 y_step: int = 5, parent=None):
        super().__init__(parent)
        self.setMinimumSize(240, 150)
        self._x_labels = x_labels
        self._series = series          # list of (name, colour, values)
        self._y_max = y_max
        self._y_step = y_step

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)
        w, h = self.width(), self.height()
        m_left, m_right, m_top, m_bottom = 22, 8, 8, 20
        plot_w = w - m_left - m_right
        plot_h = h - m_top - m_bottom

        steps = self._y_max // self._y_step
        font_sm = QtGui.QFont("Segoe UI", 8)
        p.setFont(font_sm)
        for i in range(steps + 1):
            val = i * self._y_step
            gy = m_top + plot_h - (val / self._y_max) * plot_h
            p.setPen(QtGui.QColor(_BORDER))
            p.drawLine(QtCore.QPointF(m_left, gy), QtCore.QPointF(w - m_right, gy))
            p.setPen(QtGui.QColor(_TEXT_GREY))
            p.drawText(QtCore.QRectF(0, gy - 7, m_left - 4, 14),
                       Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter, str(val))

        n = len(self._x_labels)
        if n < 2:
            p.end()
            return
        step_x = plot_w / (n - 1)

        def xy(i, val):
            gx = m_left + i * step_x
            gy = m_top + plot_h - (val / self._y_max) * plot_h
            return QtCore.QPointF(gx, gy)

        for _, colour, values in self._series:
            pts = [xy(i, v) for i, v in enumerate(values)]
            p.setPen(QtGui.QPen(QtGui.QColor(colour), 2))
            for i in range(len(pts) - 1):
                p.drawLine(pts[i], pts[i + 1])
            p.setBrush(QtGui.QColor(_WHITE))
            p.setPen(QtGui.QPen(QtGui.QColor(colour), 2))
            for pt in pts:
                p.drawEllipse(pt, 3, 3)

        p.setPen(QtGui.QColor(_TEXT_GREY))
        p.setFont(font_sm)
        for i, label in enumerate(self._x_labels):
            gx = m_left + i * step_x
            p.drawText(QtCore.QRectF(gx - 18, m_top + plot_h + 4, 36, 14),
                       Qt.AlignmentFlag.AlignCenter, label)
        p.end()


