    """
    Full Clearances page — slots into the Industrial Attachment sub-tab stack
    (or stackedWidget_2 index 6).

    Layout
    ──────
    Left scroll area
      • Page header + breadcrumb
      • 5 stat cards (Total / Cleared / In Progress / Pending / Not Cleared)
      • Filter row (Status / Department / Type / Date Range / Search / Actions)
      • Clearances List section: table + pagination
      • Bottom analytics row: dept bars | status trend | avg time | completion gauge
    Right panel (fixed 280px)
      • Clearance Overview donut
      • Clearance Types breakdown
      • Quick Actions
    """

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setObjectName("Clearances_Page")
        self.setStyleSheet(f"background:{_BG};")
        self._clearances = list(SAMPLE_CLEARANCES)
        self._build_ui()
        self._populate_table()

    # ──────────────────────────────────────────────────────────────────────────
    def _build_ui(self):
        outer = QtWidgets.QHBoxLayout(self)
